foreach ( $new_faqs as $post_id => $faqs_to_add ) {
    $existing = get_post_meta( $post_id, '_roden_faqs', true );
    if ( ! is_array( $existing ) ) {
        $existing = [];
    }

    $added = 0;
    foreach ( $faqs_to_add as $faq ) {
        // Check for duplicate questions (fuzzy match on first 40 chars).
        $dominated = false;
        foreach ( $existing as $e ) {
            if ( stripos( $e['question'], substr( $faq['question'], 0, 40 ) ) !== false ) {
                $dominated = true;
                break;
            }
        }
        if ( ! $dominated ) {
            $existing[] = $faq;
            $added++;
        }
    }

    update_post_meta( $post_id, '_roden_faqs', $existing );
    $total = count( $existing );
    WP_CLI::log( "Post {$post_id}: added {$added} FAQs (total now: {$total})" );
}

WP_CLI::success( 'Q&A gap FAQs seeded.' );
